kernel void BFS_1(
    const Node* h_graph_nodes,
    const int* h_graph_edges,
    char* h_graph_mask,
    char* h_updating_graph_mask,
    const char* h_graph_visited,
    int* h_cost,
    int no_of_nodes)
{
    int x_12 = get_global_id(0);
    if (x_12 >= no_of_nodes) return;

    if (h_graph_mask[x_12] == 1) {
        h_graph_mask[x_12] = 0;
        int start = h_graph_nodes[x_12].starting;
        int end = start + h_graph_nodes[x_12].no_of_edges;
        for (int i = start; i < end; i++) {
            int x_3 = h_graph_edges[i];
            if (h_graph_visited[x_3] == 0) {
                h_cost[x_3] = h_cost[x_12] + 1;
                h_updating_graph_mask[x_3] = 1;
            }
        }
    }
}

kernel void BFS_2(
    char* h_graph_mask,
    char* h_updating_graph_mask,
    char* h_graph_visited,
    char* stop,
